async function seed() {
  const conn = await mysql.createConnection(DATABASE_URL);

  // Generate dates starting from today, going forward 30 days
  const today = new Date();
  // Adjust to Rome timezone
  const romeOffset = new Intl.DateTimeFormat("en-CA", {
    timeZone: "Europe/Rome",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).format(today);

  const [y, m, d] = romeOffset.split("-").map(Number);
  const startDate = new Date(y, m - 1, d);

  for (let i = 0; i < editions.length; i++) {
    const date = new Date(startDate);
    date.setDate(startDate.getDate() + i);
    const dateStr = date.toISOString().slice(0, 10);
    const editionNum = i + 1;
    const ed = editions[i];

    await conn.execute(
      `INSERT INTO daily_editions (
        editionDate, editionNumber, headline, editorialP1, editorialP2, editorialP3,
        imageCaption, statsTitle,
        stat1Number, stat1Suffix, stat1Label, stat1Desc, stat1Source,
        stat2Number, stat2Suffix, stat2Label, stat2Desc, stat2Source,
        stat3Number, stat3Suffix, stat3Label, stat3Desc, stat3Source,
        quote, ctaTitle, ctaText
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON DUPLICATE KEY UPDATE
        headline = VALUES(headline),
        editorialP1 = VALUES(editorialP1),
        editorialP2 = VALUES(editorialP2),
        editorialP3 = VALUES(editorialP3),
        imageCaption = VALUES(imageCaption),
        statsTitle = VALUES(statsTitle),
        stat1Number = VALUES(stat1Number),
        stat1Suffix = VALUES(stat1Suffix),
        stat1Label = VALUES(stat1Label),
        stat1Desc = VALUES(stat1Desc),
        stat1Source = VALUES(stat1Source),
        stat2Number = VALUES(stat2Number),
        stat2Suffix = VALUES(stat2Suffix),
        stat2Label = VALUES(stat2Label),
        stat2Desc = VALUES(stat2Desc),
        stat2Source = VALUES(stat2Source),
        stat3Number = VALUES(stat3Number),
        stat3Suffix = VALUES(stat3Suffix),
        stat3Label = VALUES(stat3Label),
        stat3Desc = VALUES(stat3Desc),
        stat3Source = VALUES(stat3Source),
        quote = VALUES(quote),
        ctaTitle = VALUES(ctaTitle),
        ctaText = VALUES(ctaText)`,
      [
        dateStr, editionNum, ed.headline, ed.editorialP1, ed.editorialP2, ed.editorialP3,
        ed.imageCaption, ed.statsTitle,
        ed.stat1[0], ed.stat1[1], ed.stat1[2], ed.stat1[3], ed.stat1[4],
        ed.stat2[0], ed.stat2[1], ed.stat2[2], ed.stat2[3], ed.stat2[4],
        ed.stat3[0], ed.stat3[1], ed.stat3[2], ed.stat3[3], ed.stat3[4],
        ed.quote, ed.ctaTitle, ed.ctaText,
      ]
    );

    console.log(`✓ Edition ${editionNum} → ${dateStr}: ${ed.headline.slice(0, 50)}...`);
  }

  await conn.end();
  console.log(`\n✅ Seeded ${editions.length} daily editions starting from ${romeOffset}`);
}

seed().catch(console.error);
